class Solution {
public:
    bool checkPalindromeFormation(string a, string b) {
        int n = a.size();
        for (int i = 0; i <= n; ++i) {
            string prefixA = a.substr(0, i);
            string suffixA = a.substr(i);
            string prefixB = b.substr(0, i);
            string suffixB = b.substr(i);
            if (isPalindrome(prefixA + suffixB) || isPalindrome(prefixB + suffixA)) {
                return true;
            }
        }
        return false;
    }
    bool isPalindrome(string s) {
        int left = 0;
        int right = s.size() - 1;
        while (left < right) {
            if (s[left] != s[right]) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
};
